# -*- coding: utf-8 -*-
"""Build 3500-4500 char chapters from scene blocks."""
import re
from pathlib import Path

def count(s):
    return len(re.sub(r'\s', '', s))

def mk(title, scenes):
    body = "\n\n".join(scenes)
    return (title, body)

